1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote - base premiums and processing fee", () => {
6	    it("empty item list yields premium 5 G (only the processing fee)", () => {
7	      const result = quote({ customer: { yearsWithMHPCO: 0 }, items: [] });
8	      expect(result.premium).toBe(5);
9	    });
10	    it("a single plain sword (newcomer, first contract) yields base premium 100 G + 10 G first-insurance surcharge + 5 G fee = 115 G", () => {
11	      const result = quote({
12	        customer: { yearsWithMHPCO: 1, previousContracts: 0 },
13	        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
14	      });
15	      expect(result.premium).toBe(115);
16	    });
17	    it.todo("a single plain amulet yields base premium 60 G + fee");
18	    it.todo("a single plain staff yields base premium 80 G + fee");
19	    it.todo("a single plain potion yields base premium 40 G + fee");
20	  });
21	
22	  describe("quote - components and building blocks", () => {
23	    it.todo("2 runes yield 50 G base premium (25 each, no block)");
24	    it.todo("3 runes yield 60 G base premium (block applies)");
25	    it.todo("4 runes yield 100 G base premium (no block - block requires exactly 3)");
26	    it.todo("7 runes yield 175 G base premium (no block for any group of size != 3)");
27	    it.todo("2 runes + 1 moonstone yield 75 G base premium (no block: different types)");
28	    it.todo("3 runes + 3 moonstones yield 120 G base premium (two separate blocks)");
29	  });
30	
31	  describe("quote - item-specific modifiers", () => {
32	    it.todo("a cursed sword adds 50% of the sword's base premium as curse surcharge");
33	    it.todo("a sword with enchantment exactly 5 adds the 30% high-enchantment surcharge");
34	    it.todo("a sword with enchantment 4 does not add the high-enchantment surcharge");
35	    it.todo("a cursed sword with enchantment 5 adds both curse and high-enchantment surcharges");
36	  });
37	
38	  describe("quote - policy-wide modifiers", () => {
39	    it.todo("a customer with exactly 2 years with MHPCO gets the 20% loyalty discount");
40	    it.todo("a first insurance (customer's first contract) adds a 10% surcharge on the policy base");
41	    it.todo("a follow-up contract (not the first) applies a 15% discount on the policy base");
42	  });
43	
44	  describe("quote - multi-item policies and modifier scope", () => {
45	    it.todo("a policy covering a cursed sword and a plain amulet yields policy base 160 G plus 50 G curse surcharge = 210 G before further modifiers and fee");
46	  });
47	
48	  describe("quote - rounding", () => {
49	    it.todo("a premium calculation that yields 197.5 G is rounded up to 198 G");
50	  });
51	
52	  describe("quote - integration examples", () => {
53	    it.todo("newcomer (0 years, no previous contract) with a cursed steel sword enchantment 3 yields premium 165 G");
54	    it.todo("3-year customer's second quote with a cursed steel sword enchantment 7 yields premium 160 G");
55	  });
56	
57	  describe("claim - standard reimbursement and deductible", () => {
58	    it.todo("a regular sword (steel, enchantment 3) with 500 G damage yields payout 400 G");
59	    it.todo("damage to a rune (insurance value 250 G) of 200 G yields payout 100 G");
60	    it.todo("a dragon attack damaging an insured sword (500 G) and insured amulet (300 G) yields payout 600 G (deductible per damage event)");
61	  });
62	
63	  describe("claim - special clauses", () => {
64	    it.todo("a steel sword with enchantment 9 and damage 1000 G yields payout 400 G (50% rule then deductible)");
65	    it.todo("a dragon-material sword with enchantment 5 and damage 800 G yields payout 700 G (dragon material full reimbursement then deductible)");
66	    it.todo("a dragon-material sword with enchantment 9 and damage 1000 G yields payout 400 G (50% rule wins, then deductible)");
67	    it.todo("a dragon-material sword with enchantment exactly 8 and damage 1000 G yields payout 400 G (high-enchantment clause then deductible)");
68	  });
69	
70	  describe("claim - cap exhaustion", () => {
71	    it.todo("a policy covering a sword and an amulet has insurance sum 1600 G and cap 3200 G");
72	    it.todo("a cursed sword policy has cap 2000 G (based on unmodified insurance value)");
73	    it.todo("a policy with a sword and 3 runes has insurance sum 1750 G (block discount does not affect insurance sum)");
74	    it.todo("two successive 1500 G claims on a sword policy yield payouts 1400 G then 600 G (cap exhausted)");
75	  });
76	
77	  describe("claim - multiple items of the same type", () => {
78	    it.todo("a policy covering two swords has insurance sum 2000 G and cap 4000 G");
79	    it.todo("a dragon attack damaging both insured swords treats each damage entry as separate with its own deductible");
80	  });
81	
82	  describe("claim - rounding", () => {
83	    it.todo("a payout calculation yielding 350.5 G is rounded down to 350 G");
84	  });
